// WalletManager.kt
package com.example.payment

import android.content.Context
import android.content.SharedPreferences
import java.math.BigDecimal

class WalletManager(context: Context) {

    private val sharedPrefs: SharedPreferences = context.getSharedPreferences("wallet_prefs", Context.MODE_PRIVATE)

    fun addFunds(amount: BigDecimal) {
        val currentBalance = getBalance()
        val newBalance = currentBalance.add(amount)
        saveBalance(newBalance)
    }

    fun deductFunds(amount: BigDecimal): Boolean {
        val currentBalance = getBalance()
        return if (currentBalance >= amount) {
            val newBalance = currentBalance.subtract(amount)
            saveBalance(newBalance)
            true
        } else {
            false // Insufficient funds
        }
    }

    fun getBalance(): BigDecimal {
        val balance = sharedPrefs.getString("balance", "0.00")
        return BigDecimal(balance)
    }

    private fun saveBalance(balance: BigDecimal) {
        with(sharedPrefs.edit()) {
            putString("balance", balance.toPlainString())
            apply()
        }
    }
}